G?n?re un CV structur? avec les sections suivantes dans cet ordre exact :
1. PROFIL - 3 ? 5 phrases synth?tisant l'expertise, les ann?es d'exp?rience et la valeur ajout?e du candidat
2. COMP?TENCES CL?S - 4 comp?tences principales avec une ligne de d?tail chacune
3. EXP?RIENCE PROFESSIONNELLE - Pour chaque exp?rience : employeur en majuscules, lieu, poste en gras, p?riode, puis sous-sections Contexte / R?alisations / R?sultats
4. FORMATION - dipl?mes avec ann?e et ?tablissement
5. CERTIFICATIONS - si applicable
6. LANGUES - avec niveaux

R?ponds UNIQUEMENT avec un JSON valide sans aucun texte autour, sans balises markdown, strictement ce format :
{
  "profil": "texte du profil",
  "competences": [
    {"titre": "Comp?tence 1", "detail": "description"},
    {"titre": "Comp?tence 2", "detail": "description"},
    {"titre": "Comp?tence 3", "detail": "description"},
    {"titre": "Comp?tence 4", "detail": "description"}
  ],
  "experiences": [
    {
      "employeur": "NOM EMPLOYEUR",
      "lieu": "Ville",
      "poste": "Intitul? du poste",
      "periode": "2020 - aujourd'hui",
      "contexte": "texte contexte",
      "realisations": "texte r?alisations",
      "resultats": "texte r?sultats"
    }
  ],
  "formation": [
    {"annee": "2018", "etablissement": "Nom ?cole", "diplome": "Titre du dipl?me"}
  ],
  "certifications": "texte ou vide",
  "langues": "texte langues et niveaux"
}`;

const body = JSON.stringify({
  model: "claude-opus-4-5",
  max_tokens: 4096,
  messages: [{ role: "user", content: prompt }]
});

return [{ json: { body } }];

const text = $input.first().json.content[0].text;

// Nettoyer les balises markdown si pr?sentes
const clean = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let cv;
try {
  cv = JSON.parse(clean);
} catch(e) {
  throw new Error('JSON invalide : ' + e.message + '\n\nTexte re?u : ' + clean);
}

return [{ json: { cv, email: $('Code in JavaScript').item.json.email, nom: $('Code in JavaScript').item.json.nom } }];

const d = $('Parser CV').item.json;
const cv = d.cv;

const competences = cv.competences
  .map(c => `${c.titre} : ${c.detail}`)
  .join('\n');

const experiences = cv.experiences.map(e =>
  `${e.periode}  ${e.employeur}\n` +
  `   ${e.poste}\n` +
  `   Contexte : ${e.contexte}\n` +
  `   R?alisations : ${e.realisations}\n` +
  `   R?sultats : ${e.resultats}`
).join('\n\n');

const formation = cv.formation
  .map(f => `${f.annee}  ${f.etablissement} | ${f.diplome}`)
  .join('\n');

const langues_certifications =
  `Langues : ${cv.langues}` +
  (cv.certifications ? `\nCertifications : ${cv.certifications}` : '');

const requests = [
  { old: '{{NOM}}',                   new_val: d.nom },
  { old: '{{INFOS_PERSO}}',           new_val: '' },
  { old: '{{PROFIL}}',                new_val: cv.profil },
  { old: '{{COMPETENCES}}',           new_val: competences },
  { old: '{{EXPERIENCES}}',           new_val: experiences },
  { old: '{{FORMATION}}',             new_val: formation },
  { old: '{{LANGUES_CERTIFICATIONS}}',new_val: langues_certifications },
].map(r => ({
  replaceAllText: {
    containsText: { text: r.old, matchCase: true },
    replaceText: r.new_val || ''
  }
}));

return [{
  json: {
    requestsBody: JSON.stringify({ requests }),
    nom: d.nom,
    email: d.email,
  }
}];

